with payload as (
  select $_hc$[{"id":"artic-crazy-quilt-with-animals-181720","title":"'Crazy Quilt' with Animals","maker":"Florence Elizabeth Marvin","culture":"Brooklyn Heights","country":null,"region":null,"date_display":"1886","category":"textile","image_url":"https://www.artic.edu/iiif/2/20692004-784b-0c7b-9a15-0db2dd6e83e4/full/843,/0/default.jpg","source_name":"Art Institute of Chicago","source_url":"https://www.artic.edu/artworks/181720","license":"Public domain / Art Institute of Chicago","hook":"A textile from Brooklyn Heights, 1886, with animal, bird, and cat bringing its subject into focus.","story":"'Crazy Quilt' with Animals is a textile by Florence Elizabeth Marvin, from Brooklyn Heights, dated 1886, made with pieced and embroidered \"crazy\" quilt. It was made through slow handwork, where use, display, pattern, and memory could share the same surface. The use of animal, bird, and cat anchors the composition and gives the viewer a direct point of entry into its subject.","why_it_matters":"It matters because it treats thread, pattern, and domestic labor as serious cultural evidence.","latitude":37.0902,"longitude":-95.7129,"week_key":"full-archive-2026-W01"},{"id":"artic-basket-35716","title":"Basket","maker":null,"culture":"England","country":null,"region":null,"date_display":"c. 1645","category":"jewelry","image_url":"https://www.artic.edu/iiif/2/8c7ef82e-1cb1-9dc5-ff8a-dab29259049b/full/843,/0/default.jpg","source_name":"Art Institute of Chicago","source_url":"https://www.artic.edu/artworks/35716","license":"Public domain / Art Institute of Chicago","hook":"A piece of jewelry from England, c. 1645, with animal, basket, and deer bringing its subject into focus.","story":"Basket is a piece of jewelry from England, dated c. 1645, made with metal frame worked with glass beads, applied motifs of gold and silver leafed paper and linen. It was made to be worn, so its meaning depended on closeness to the body as much as visual display. The use of animal, basket, and deer an