insert into public.culture_items (
  id,
  title,
  maker,
  culture,
  country,
  region,
  date_display,
  category,
  image_url,
  source_name,
  source_url,
  license,
  hook,
  story,
  why_it_matters,
  latitude,
  longitude,
  week_key
)
select
  id,
  title,
  maker,
  culture,
  country,
  region,
  date_display,
  category,
  image_url,
  source_name,
  source_url,
  license,
  hook,
  story,
  why_it_matters,
  latitude,
  longitude,
  week_key
from jsonb_to_recordset((select doc from payload)) as x(
  id text,
  title text,
  maker text,
  culture text,
  country text,
  region text,
  date_display text,
  category text,
  image_url text,
  source_name text,
  source_url text,
  license text,
  hook text,
  story text,
  why_it_matters text,
  latitude double precision,
  longitude double precision,
  week_key text
);

